/* Packcheck — icon render core v2.
   PNG-based icons (data URIs at 2x/168px) for the 17 traced icons.
   Bear + checkbox remain as stroke-path glyphs for flexibility. */
(function(){
const COL={pine:'#2e4a39',pineDeep:'#243b2d',scout:'#c5172b',gold:'#d6a93f',
  canvas:'#d8c39e',cream:'#f4ecd8',paper:'#efe6cf',charcoal:'#1c1c1a',ink:'#5d5240'};

// PNG icons (base64 at 168×168 — tile appearance baked in)
const PNG={
  pack:`data:image/png;base64,`,
  sleep:`data:image/png;base64,`,
  poles:`data:image/png;base64,`,
  jacket:`data:image/png;base64,`,
  rain:`data:image/png;base64,`,
  soap:`data:image/png;base64,`,
  food:`data:image/png;base64,`,
  bottle:`data:image/png;base64,`,
  knife:`data:image/png;base64,`,
  chair:`data:image/png;base64,`,
  cook:`data:image/png;base64,`,
  compass:`data:image/png;base64,`,
  trowel:`data:image/png;base64,`,
  tape:`data:image/png;base64,`,
  consum:`data:image/png;base64,`,
  box:`data:image/png;base64,`,
  bear:`data:image/svg+xml;base64,`,
};

// Stroke-path icons (checkbox brand lockup, tent fallback)
const STROKE={
  checkbox:{base:`<rect x="22" y="22" width="56" height="56" rx="4"/>`,accent:`<path d="M33 52 L46 65 L69 35"/>`},
  tent:{base:`<line x1="12" y1="78" x2="88" y2="78"/><line x1="50" y1="24" x2="18" y2="78"/><line x1="50" y1="24" x2="82" y2="78"/>`,accent:`<path d="M50 78 L40 78 L50 52 Z"/>`},
};

// All keys in display order
const ALL_KEYS=['pack','sleep','poles','jacket','rain','soap',
  'food','bottle','knife','chair','cook','bear',
  'compass','trowel','tape','consum','box','checkbox'];

// treatment configs (B = Camp Badge default)
const TREAT={
  A:{name:'Trail Monoline', ic:COL.charcoal, ac:COL.scout, bw:6,
     tile:{background:'#fff', border:'1px solid rgba(28,28,26,.14)', radius:11}},
  B:{name:'Camp Badge', ic:COL.cream, ac:COL.scout, bw:6,
     tile:{background:COL.pine, border:'1px solid rgba(193,23,43,.55)', radius:21,
       shadow:'inset 0 0 0 3px '+COL.pine+', inset 0 0 0 4px rgba(193,23,43,.4)'}},
  C:{name:'Field Two-Tone', ic:COL.charcoal, ac:COL.scout, bw:7,
     tile:{background:COL.canvas, border:'1px solid rgba(28,28,26,.2)', radius:14}},
};

// Render a glyph. PNG icons ignore ic/ac/bw — appearance is baked in.
function glyph(key,opts){
  const o=Object.assign({ic:COL.charcoal,ac:COL.scout,bw:6,size:52},opts);
  if(PNG[key]){
    const r=Math.round(o.size*0.25);
    return `<img src="${PNG[key]}" width="${o.size}" height="${o.size}" style="display:block;border-radius:${r}px">`;
  }
  const d=STROKE[key]; if(!d) return '';
  return `<svg viewBox="0 0 100 100" width="${o.size}" height="${o.size}" style="display:block">`+
    `<g fill="none" stroke="${o.ic}" stroke-width="${o.bw}" stroke-linecap="round" stroke-linejoin="round">${d.base}</g>`+
    `<g fill="none" stroke="${o.ac}" stroke-width="${o.bw}" stroke-linecap="round" stroke-linejoin="round">${d.accent}</g>`+
    `</svg>`;
}

// Glyph inside its treatment tile.
function tile(key,t,tileSize,iconSize){
  const cfg=TREAT[t]||TREAT.B; const ts=tileSize||84, is=iconSize||Math.round(ts*0.62);
  if(PNG[key]){
    // PNG icons have the tile appearance baked in — just size and clip
    const r=Math.round(ts*0.25);
    return `<div style="width:${ts}px;height:${ts}px;display:inline-flex;align-items:center;justify-content:center;overflow:hidden;border-radius:${r}px"><img src="${PNG[key]}" width="${ts}" height="${ts}" style="display:block;border-radius:${r}px"></div>`;
  }
  const st=cfg.tile;
  const r=Math.round(ts*0.25);
  const css=`width:${ts}px;height:${ts}px;display:flex;align-items:center;justify-content:center;`+
    `background:${st.background};border:${st.border};border-radius:${r}px;`+
    (st.shadow?`box-shadow:${st.shadow};`:'')+'overflow:hidden';
  return `<div style="${css}">${glyph(key,{ic:cfg.ic,ac:cfg.ac,bw:cfg.bw,size:is})}</div>`;
}

window.PCIcon={glyph,tile,PNG,STROKE,TREAT,COL,
  keys:ALL_KEYS};
})();